css:
.schedule-sheet { font-size: 11px; color: #000; }
.schedule-sheet table { width: 100%; border-collapse: collapse; table-layout: fixed; }
.schedule-sheet td { border: 1px solid #000; padding: 4px 6px; vertical-align: middle; }
.schedule-sheet .date-title { background: #fff200; font-size: 22px; font-weight: 800; letter-spacing: 0.5px; text-align: center; text-transform: uppercase; }
.schedule-sheet .session-morning { background: #f3a3d9; font-size: 16px; font-style: italic; font-weight: 700; text-align: center; }
.schedule-sheet .session-afternoon { background: #17a8e5; color: #fff; font-size: 16px; font-weight: 700; text-align: center; }
.schedule-sheet .name-col { width: 22%; font-weight: 700; text-align: center; }
.schedule-sheet .assignment-col { width: 56%; font-weight: 700; text-align: center; text-transform: uppercase; }
.schedule-sheet .room-col { width: 10%; text-align: center; font-weight: 700; }
.schedule-sheet .ref-col { width: 12%; text-align: center; }
.schedule-sheet .blank-cell { background: #f7f7f7; }
.schedule-sheet .alert-row td { background: #ff1e1e; color: #fff; }
.schedule-sheet .info-row td { background: #e9f7ff; }
.schedule-sheet .note-primary td { background: #ff1e1e; color: #fff; font-weight: 800; text-transform: uppercase; }
.schedule-sheet .note-secondary td { background: #ffd84d; color: #000; font-weight: 800; text-transform: uppercase; }
.schedule-sheet .meta { margin: 0 0 8px; font-size: 12px; }

html:
{% set morning_rows = [] %}
{% set afternoon_rows = [] %}
{% for row in doc.entries %}
	{% if row.session == "Afternoon" %}
		{% set _ = afternoon_rows.append(row) %}
	{% else %}
		{% set _ = morning_rows.append(row) %}
	{% endif %}
{% endfor %}

<div class="schedule-sheet">
	{% if doc.location %}
		<p class="meta"><strong>Location:</strong> {{ doc.location }}</p>
	{% endif %}
	<table>
		<tr>
			<td colspan="4" class="date-title">{{ doc.schedule_title or frappe.utils.formatdate(doc.schedule_date, "MMM dd, yyyy")|upper }}</td>
		</tr>

		{% if morning_rows %}
		<tr>
			<td colspan="4" class="session-morning">{{ doc.morning_session_label or "8AM" }}</td>
		</tr>
		{% for row in morning_rows %}
		<tr class="{% if row.row_style == "Alert" %}alert-row{% elif row.row_style == "Info" %}info-row{% endif %}">
			<td class="name-col">{{ row.assignee_name }}</td>
			<td class="assignment-col">{{ row.assignment_details }}</td>
			<td class="room-col">
    {% if row.room_or_batch %}
        {{ frappe.db.get_value("Room", row.room_or_batch, "room_name") or row.room_or_batch }}
    {% endif %}
</td>
			<td class="ref-col">{{ row.reference_info or "" }}</td>
		</tr>
		{% endfor %}
		{% endif %}

		{% if afternoon_rows %}
		<tr>
			<td colspan="4" class="session-afternoon">{{ doc.afternoon_session_label or "1PM" }}</td>
		</tr>
		{% for row in afternoon_rows %}
		<tr class="{% if row.row_style == "Alert" %}alert-row{% elif row.row_style == "Info" %}info-row{% endif %}">
			<td class="name-col">{{ row.assignee_name }}</td>
			<td class="assignment-col">{{ row.assignment_details }}</td>
			<td class="room-col">
    {% if row.room_or_batch %}
        {{ frappe.db.get_value("Room", row.room_or_batch, "room_name") or row.room_or_batch }}
    {% endif %}
</td>
			<td class="ref-col">{{ row.reference_info or "" }}</td>
		</tr>
		{% endfor %}
		{% endif %}

		{% if doc.note_primary %}
		<tr class="note-primary">
			<td colspan="4">{{ doc.note_primary }}</td>
		</tr>
		{% endif %}
		{% if doc.note_secondary %}
		<tr class="note-secondary">
			<td colspan="4">{{ doc.note_secondary }}</td>
		</tr>
		{% endif %}
	</table>
</div>
